const intent = $json.intent || '';
const params = $json.intentParams || {};
const GOOGLE_API_KEY = $env.GOOGLE_API_KEY || '';
const accessToken = $env.GOOGLE_ACCESS_TOKEN || '';

if (!GOOGLE_API_KEY && !accessToken) {
  return [{ json: { ...$json, responseText: '⚠️ Google API credentials not configured.', success: false } }];
}

let endpoint, queryParams, method = 'GET', body = null;
const tasklist = params.tasklist_id || '@default';

if (intent === 'tasks_list') {
  endpoint = `https://tasks.googleapis.com/tasks/v1/lists/${tasklist}/tasks`;
  queryParams = { showCompleted: String(params.show_completed !== false), maxResults: 50 };
} else if (intent === 'tasks_create') {
  const { title, notes, due } = params;
  if (!title) return [{ json: { ...$json, responseText: '❗ Title required.', success: false } }];
  endpoint = `https://tasks.googleapis.com/tasks/v1/lists/${tasklist}/tasks`;
  method = 'POST';
  body = { title };
  if (notes) body.notes = notes;
  if (due) body.due = due;
} else if (intent === 'tasks_update') {
  const taskId = params.task_id || params.id;
  if (!taskId) return [{ json: { ...$json, responseText: '❗ Task ID required.', success: false } }];
  endpoint = `https://tasks.googleapis.com/tasks/v1/lists/${tasklist}/tasks/${taskId}`;
  method = 'PATCH';
  body = {};
  if (params.title !== undefined) body.title = params.title;
  if (params.status !== undefined) body.status = params.status;
  if (params.notes !== undefined) body.notes = params.notes;
} else if (intent === 'tasks_delete') {
  const taskId = params.task_id || params.id;
  if (!taskId) return [{ json: { ...$json, responseText: '❗ Task ID required.', success: false } }];
  endpoint = `https://tasks.googleapis.com/tasks/v1/lists/${tasklist}/tasks/${taskId}`;
  method = 'DELETE';
} else {
  return [{ json: { ...$json, responseText: '❓ Unknown Tasks intent: ' + intent, success: false } }];
}

return [{ json: { ...$json, apiEndpoint: endpoint, apiParams: queryParams, apiMethod: method, apiBody: body } }];

const items = $json.items || [];
if ($json.id && !$json.items) {
  // Create, update, or delete result
  return [{ json: { ...$input.item.json, responseText: '✅ Task operation completed.', success: true } }];
}
if (items.length === 0) {
  return [{ json: { ...$input.item.json, responseText: '📋 No tasks found.', success: true } }];
}
let text = '📋 Tasks:

';
items.forEach((t, i) => {
  const status = t.status === 'completed' ? '✅' : '⬜';
  const title = t.title || 'Untitled';
  const due = t.due ? ` (Due: ${t.due.split('T')[0]})` : '';
  text += `${status} ${title}${due}\n`;
});
return [{ json: { ...$input.item.json, responseText: text, success: true } }];
